const express = require('express');
const oauth2orize = require('oauth2orize');
const passport = require('passport');
const crypto = require('crypto');
const redis = require('redis');

const client = redis.createClient({ host: 'localhost', port: 6379 });

client.on('error', (err) => console.error('REDIS error:', err));

// create OAuth 2 server
const server = oauth2orize.createServer();

const app = express();

// Session middleware
app.use(passport.initialize());
app.use(passport.session());

server.exchange(oauth2orize.exchange.refreshToken(
  async (client, refreshToken, scope, done) => {
    client.get(refreshToken, (err, token) => {
      if (err) { return done(err); }
      if (!token) { return done(null, false); }

      const newAccessToken = crypto.randomBytes(32).toString('hex');
      // Save the access token and the user it belongs to in Redis
      client.set(newAccessToken, token.userId, 'EX', 60*60*24*365, (err) => {
        if (err) { return done(err); }

        done(null, newAccessToken);
      });
    });
}));

// OAuth token endpoint
app.post('/token', (req, res, next) => {
  let middleware = passport.authenticate(['basic', 'oauth2-client-password'], { session: false });
  middleware(req, res, () => {
    server.token()(req, res, next);
  });
});